                    if (newCost < minCost[ni][nj][stepMod]) {
                        minCost[ni][nj][stepMod] = newCost;
                        heap.push([newCost, ni, nj, nextStep]);
                    }
                }
            }
        } else {
            // Even step: must wait
            const nextStep = step + 1;
            const waitCostHere = waitCost[i][j];
            const newCost = currentCost + waitCostHere;
            const stepMod = nextStep % 2;
            if (newCost < minCost[i][j][stepMod]) {
                minCost[i][j][stepMod] = newCost;
                heap.push([newCost, i, j, nextStep]);
            }
        }
    }

    return -1; // should not reach here if m,n >= 1
}
